sql:
SELECT name 
FROM plugins 
WHERE total_ratings = (SELECT MAX(total_ratings) FROM plugins);

SELECT name, AVG(average_rating) AS average_rating, SUM(total_ratings) AS total_ratings
FROM plugins
GROUP BY name;

SELECT plugin_id, COUNT(tag_id)
FROM plugin_tags
GROUP BY plugin_id;

SELECT plugin_id, AVG(rating) AS average_rating, COUNT(rating) AS total_ratings
FROM plugin_feedback
GROUP BY plugin_id;
